// Payload: phone, code, route, evolution_instance (Edge send-whatsapp-verification)
// Base da Evolution SEM $env (n8n 2.x pode bloquear $env no Code → "access to env vars denied")
const EVOLUTION_BASE_DEFAULT = 'http://72.60.159.183:8080';
const item = $input.first().json;
const body = item.body && typeof item.body === 'object' ? item.body : item;
const phone = String(body.phone || '').replace(/\D/g, '');
const number = phone.startsWith('55') ? phone : (phone ? '55' + phone : '');
const code = String(body.code || '').trim();
const route = body.route === 'MASTER_TO_OWNER' ? 'MASTER_TO_OWNER' : 'SHOP_TO_CLIENT';
const inst = String(body.evolution_instance || 'caio_zap').trim().replace(/[^a-zA-Z0-9_-]/g, '') || 'caio_zap';
let base = String(EVOLUTION_BASE_DEFAULT);
if (base.endsWith('/')) base = base.slice(0, -1);
const sendUrl = base + '/message/sendText/' + inst;
let message;
if (route === 'MASTER_TO_OWNER') {
  message = `🔐 *BookNow*\n\nCódigo para verificar o *dono da barbearia*:\n*${code}*\n\nVálido por 10 minutos. Não compartilhe.`;
} else {
  message = `🔐 *BookNow*\n\nSeu código de verificação:\n*${code}*\n\nVálido por 10 minutos. Não compartilhe.`;
}
return [{ json: { number, message, route, evolution_instance: inst, sendUrl, raw: body } }];
